-- =========================================================================
-- ESCO MIGRATION — PHASE 3: PASSENGERS + ARCHIVE_PASSENGERS
-- =========================================================================
-- passengers: 84 (UA→EU 34 + EU→UA 50)
-- archive_passengers: 84
--
-- FK: passengers.vehicle_id → vehicles.id (LOOKUP по name з vehicles,
--     trim + case-insensitive; якщо не знайдено — NULL).
-- cal_id — текст, як є (співпадає з calendar.cal_id вставленим у Phase 2).
-- cli_id — NULL (у xlsx порожній у всіх).
-- Рейтинги поза [1,5] → NULL з raw-значенням у notes/extra_data.
-- Ідемпотентно: ON CONFLICT (tenant_id, pax_id|archive_id) DO NOTHING.
-- =========================================================================

BEGIN;

-- ── 1. extra_data для нелягаючих xlsx колонок ─────────────────
ALTER TABLE public.archive_passengers ADD COLUMN IF NOT EXISTS extra_data jsonb;
COMMENT ON COLUMN public.archive_passengers.extra_data IS
    'Поля xlsx-архіву без власної колонки: direction, cal_id, cli_id,
     rte_id, smart_id, таймінг, auto_id, валюта завдатку, багаж,
     коментарі, archived_by_name (бо archived_by uuid), тощо.';

-- ── 2. UNIQUE індекси ───────────────────────────────────────────
CREATE UNIQUE INDEX IF NOT EXISTS passengers_tenant_pax_uidx ON public.passengers (tenant_id, pax_id);
CREATE UNIQUE INDEX IF NOT EXISTS archive_passengers_tenant_arc_uidx ON public.archive_passengers (tenant_id, archive_id);

-- ── passengers (84 активних) ───────────────────────

-- ── archive_passengers (84 архівних) ─────────────
Schachenstrasse 17
6030 Ебікон', 'Львів', '2026-05-01'::date, NULL, NULL, 130, NULL, 0, 130, 'Не оплачено', 'Архів', NULL, NULL, NULL, false, NULL, NULL, '{"direction": "Європа-УК", "smart_id": 67738236.0, "deposit_value": 0.0, "deposit_currency": "UAH", "archived_by_name": "Менеджер"}'::jsonb) ON CONFLICT (tenant_id, archive_id) DO NOTHING;
Brühlstrasse 2', 'Львів', '2026-03-27'::date, 'Женева', 'Вільна розсадка', 100, NULL, 1000, NULL, 'Частково', 'Архів', 'женева тест 1', NULL, NULL, false, NULL, NULL, '{"direction": "Європа-УК", "cal_id": "CAL-20260327-JMKG", "smart_id": 198483374.0, "deposit_value": 1000.0, "deposit_currency": "UAH", "archived_by_name": "Менеджер"}'::jsonb) ON CONFLICT (tenant_id, archive_id) DO NOTHING;

COMMIT;

NOTIFY pgrst, 'reload schema';